<?php
namespace App\Services\Finance\VippsMobilePay; use App\Models\PaymentRecord; use Illuminate\Validation\ValidationException;
class VippsMobilePayRequestBuilder { public function create(PaymentRecord $p):array{$this->valid($p);return ['amount'=>$this->amount($p),'paymentMethod'=>['type'=>'WALLET'],'reference'=>$p->payment_number,'returnUrl'=>config('payment_providers.vipps_mobilepay.return_url'),'userFlow'=>'WEB_REDIRECT','paymentDescription'=>'BiKuBe order '.$p->order?->order_number];} public function capture(PaymentRecord $p):array{$this->valid($p);return ['modificationAmount'=>$this->amount($p)];} public function refund(PaymentRecord $p,int|float|string $amount):array{$v=(int)round(((float)$amount)*100);throw_if($v<=0,ValidationException::withMessages(['amount'=>'Refund amount must be positive.']));return ['modificationAmount'=>['currency'=>$p->currency?:'NOK','value'=>$v]];} private function amount(PaymentRecord $p):array{return ['currency'=>$p->currency?:'NOK','value'=>(int)round(((float)$p->amount)*100)];} private function valid(PaymentRecord $p):void{throw_if((float)$p->amount<=0,ValidationException::withMessages(['payment'=>'Payment amount must come from a real positive quote or invoice.']));}}
